**Path Traversal (Critical)**

`req.query.file` flows directly into `path.join`-equivalent string concat and into `res.download()`. An attacker passes `../../etc/passwd` to escape `baseDir`.

**Fix**

```js
const requested = path.resolve(baseDir, req.query.file);
if (!requested.startsWith(path.resolve(baseDir) + path.sep)) {
  return res.status(400).end();
}
res.download(requested);
```

**Verify**

- `path.resolve` collapses `..` segments before the prefix check.
- Check covers both `/` and `\` (Windows) via `path.sep`.
- Test: `file=../../etc/passwd` → 400; `file=report.pdf` → download.
- Add allowlist of extensions if feasible (`/\.(pdf|csv|zip)$/`).

```js
// before (callback style assumed)
reconcileBatch(req, res, next) { ... }

// after
async reconcileBatch(req, res, next) {
  try {
    const batch   = await loadBatch(req);
    const rows    = await db.fetchRows(batch);
    const results = await applyRules(rows);
    await db.save(results);
    emitMetrics(results);
  } catch (err) {
    return next(err);
  }
}
```

**What changed**

| | before | after |
|---|---|---|
| signature | `reconcileBatch(req, res, next)` | `async reconcileBatch(req, res, next)` |
| control flow | callbacks / `.then()` | `await` |
| db errors | inline callback checks | single `catch → next(err)` |

**Constraints held**

- Every db call (`fetchRows`, `save`) is inside the `try`, so any rejection routes to `next(err)`.  
- `emitMetrics` stays synchronous after `save`; if it can throw and you don't want that to hit `next(err)`, move it after the `try/catch`.  
- Order `load_batch → fetchRows → apply_rules → save → emit_metrics` is preserved and sequential.  
- No other logic touched.

```js
async function loadGatewayUser(req, res, next) {
  if (!req.session?.userId) return next();

  try {
    const user = await db.findUser(req.session.userId);
    await flags.load(user);
    await audit.log(user);
    req.user = user;
    next();
  } catch (err) {
    next(err);
  }
}
```

```js
async function reconcileBatch(req, res, next) {
  let rows;
  try {
    rows = await db.fetchRows(req.batchId);
  } catch (err) {
    return next(err);
  }

  const results = apply_rules(rows);

  try {
    await db.save(results);
  } catch (err) {
    return next(err);
  }

  emit_metrics(results);
  res.json(results);
}
```

```js
loadGatewayUser = async (req, res, next) => {
  try {
    if (!req.session?.userId) return next();

    const user = await db.findUser(req.session.userId);
    if (!user) return next();

    await flags.load(user);
    await audit.log(user);

    req.user = user;
    next();
  } catch (err) {
    next(err);
  }
};
```
